#include <omp.h>
#include <stdio.h>
#include <stdlib.h>

double work(int i) {
 // Simulate variable workload: iterations 0-999 take 0.1-10ms
 double start = omp_get_wtime();
 // Simulate computation (more work for higher indices)
 volatile double sum = 0;
 int iterations = 100 + (i * 1000); // Variable work
 for (int j = 0; j < iterations; j++) {
 sum += sin(j) * cos(j);
 }
 return omp_get_wtime() - start;
}

int main() {
 int n = 10000;
 double start, end, times[3];

 // Test static scheduling
 start = omp_get_wtime();
 #pragma omp parallel for schedule(static)
 for (int i = 0; i < n; i++) {
 work(i);
 }
 times[0] = omp_get_wtime() - start;

 // Test dynamic scheduling with chunk=100
 start = omp_get_wtime();
 #pragma omp parallel for schedule(dynamic, 100)
 for (int i = 0; i < n; i++) {
 work(i);
 }
 times[1] = omp_get_wtime() - start;

 // Test guided scheduling with min chunk=100
 start = omp_get_wtime();
 #pragma omp parallel for schedule(guided, 100)
 for (int i = 0; i < n; i++) {
 work(i);
 }
 times[2] = omp_get_wtime() - start;

 printf("Static: %.3fs\nDynamic: %.3fs\nGuided: %.3fs\n", 
 times[0], times[1], times[2]);
 return 0;
}

