#include <omp.h>
#include <stdio.h>
#include <string.h>

#define N 2000
#define CHUNK 64 // Cache line friendly size

void matrix_add_naive(double A[N][N], double B[N][N], double C[N][N]) {
 #pragma omp parallel for schedule(static)
 for (int i = 0; i < N; i++)
 for (int j = 0; j < N; j++)
 C[i][j] = A[i][j] + B[i][j];
}

void matrix_add_optimized(double A[N][N], double B[N][N], double C[N][N]) {
 // Static with appropriate chunk for cache tiling
 #pragma omp parallel for schedule(static, CHUNK)
 for (int i = 0; i < N; i++)
 for (int j = 0; j < N; j++)
 C[i][j] = A[i][j] + B[i][j];
}

void matrix_multiply(double A[N][N], double B[N][N], double C[N][N]) {
 // Variable workload: different row computations have different costs
 // Use guided for better balance
 #pragma omp parallel for schedule(guided, 16)
 for (int i = 0; i < N; i++) {
 for (int j = 0; j < N; j++) {
 double sum = 0;
 for (int k = 0; k < N; k++)
 sum += A[i][k] * B[k][j];
 C[i][j] = sum;
 }
 }
}

int main() {
 double A[N][N], B[N][N], C[N][N];

 // Initialize matrices
 memset(A, 0, sizeof(A));
 memset(B, 0, sizeof(B));
 memset(C, 0, sizeof(C));

 // Set number of threads
 omp_set_num_threads(8);

 double start = omp_get_wtime();
 matrix_add_optimized(A, B, C);
 printf("Optimized addition time: %.3f seconds\n", 
 omp_get_wtime() - start);

 return 0;
}

